window.ETS_LC1 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["The woman is carrying a tray of food.", "The woman is wearing a jacket.", "The woman is tying up her hair.", "The woman is removing her hat."], "optko": ["여자가 음식이 담긴 쟁반을 나르고 있다.", "여자가 재킷을 입고 있다.", "여자가 머리를 묶고 있다.", "여자가 모자를 벗고 있다."], "ans": 1, "audio": "Test_01-01.mp3", "img": "ets_t1_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["Some people are standing next to a filing cabinet.", "Some people are searching through a desk.", "Some people are watching a presentation.", "Some people are looking at a book."], "optko": ["사람들이 파일 캐비닛 옆에 서 있다.", "사람들이 책상을 샅샅이 뒤지고 있다.", "사람들이 발표를 보고 있다.", "사람들이 책을 보고 있다."], "ans": 3, "audio": "Test_01-02.mp3", "img": "ets_t1_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["A woman is holding a phone up to her ear.", "A woman is pouring a beverage into a glass.", "Some light fixtures are hanging from the ceiling.", "Some tiles are being installed in a hallway."], "optko": ["여자가 전화기를 귀에 대고 있다.", "여자가 음료를 유리잔에 따르고 있다.", "조명들이 천장에 매달려 있다.", "타일들이 복도에 설치되고 있다."], "ans": 2, "audio": "Test_01-03.mp3", "img": "ets_t1_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["A wooden crate is filled with vegetables.", "One of the men is putting vegetables into a shopping bag.", "A backpack has been set on the ground.", "One of the men is reaching into a bucket."], "optko": ["나무 상자가 채소로 가득 차 있다.", "남자들 중 한 명이 채소를 쇼핑백에 넣고 있다.", "배낭이 바닥에 놓여 있다.", "남자들 중 한 명이 양동이 속에 손을 넣고 있다."], "ans": 0, "audio": "Test_01-04.mp3", "img": "ets_t1_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["Painting supplies have been laid out on the floor.", "He's laying a brush down on a windowsill.", "He's lifting a can of paint by its handle.", "Cans of paint have been placed on a step stool."], "optko": ["페인트용 물품들이 바닥에 펼쳐져 있다.", "남자가 붓을 창틀에 내려놓고 있다.", "남자가 손잡이를 이용해 페인트 통을 들어 올리고 있다.", "페인트 통들이 계단식 발판에 놓여 있다."], "ans": 0, "audio": "Test_01-05.mp3", "img": "ets_t1_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["A path is covered with fallen branches.", "A tree is lying across a grassy area.", "Some water has pooled on a path.", "Some cyclists are riding through a field."], "optko": ["길이 떨어진 나뭇가지들로 덮여 있다.", "나무가 풀밭을 가로질러 놓여 있다.", "길에 물이 고여 있다.", "자전거 타는 사람들이 들판을 지나 달리고 있다."], "ans": 2, "audio": "Test_01-06.mp3", "img": "ets_t1_q6.jpg"}, {"n": 7, "part": 2, "q": "Where is the conference being held?", "qko": "회의는 어디에서 열리나요?", "opts": ["A three-day vacation.", "At the Riverview Hotel.", "In the supply cabinet."], "optko": ["3일간의 휴가요.", "리버뷰 호텔에서요.", "비품 캐비닛 안에요."], "ans": 1, "audio": "Test_01-07.mp3"}, {"n": 8, "part": 2, "q": "When does the warehouse manager arrive?", "qko": "창고 관리자가 언제 도착하나요?", "opts": ["Sure, no problem.", "About twelve shipping boxes.", "Not until this afternoon."], "optko": ["물론이죠, 문제없습니다.", "약 12개의 배송용 상자들이요.", "오늘 오후나 되어야 합니다."], "ans": 2, "audio": "Test_01-08.mp3"}, {"n": 9, "part": 2, "q": "There's a nice park nearby, right?", "qko": "근처에 멋진 공원이 있죠, 그렇죠?", "opts": ["Did you order paper for the copier?", "Yes—it's next to Greendale Lake.", "They're in the parking garage."], "optko": ["복사 용지를 주문했나요?", "네, 그린데일 호수 옆에 있습니다.", "그들은 주차장에 있습니다."], "ans": 1, "audio": "Test_01-09.mp3"}, {"n": 10, "part": 2, "q": "Who sent the meeting minutes to the accounting department?", "qko": "누가 회의록을 회계부에 보냈나요?", "opts": ["Our office assistant.", "They have a savings account.", "Cash and credit cards."], "optko": ["우리 사무 보조 직원이요.", "그들은 저축 예금 계좌를 갖고 있어요.", "현금과 신용카드요."], "ans": 0, "audio": "Test_01-10.mp3"}, {"n": 11, "part": 2, "q": "I'd like to know what you think of our new finance analyst.", "qko": "우리 신임 재무 분석가를 어떻게 생각하시는지 알고 싶어요.", "opts": ["I've prepared the decorations for tomorrow.", "He seems very competent.", "It's finally stopped raining."], "optko": ["제가 내일 사용할 장식들을 준비해 놨어요.", "그분은 아주 유능하신 것 같아요.", "드디어 비가 그쳤네요."], "ans": 1, "audio": "Test_01-11.mp3"}, {"n": 12, "part": 2, "q": "Let's go on the company retreat.", "qko": "회사 야유회를 갑시다.", "opts": ["Oh, did he?", "Yes, that's a good idea.", "He tried to solve that problem."], "optko": ["아, 그가 그랬나요?", "네, 좋은 생각입니다.", "그는 그 문제를 해결하려 했어요."], "ans": 1, "audio": "Test_01-12.mp3"}, {"n": 13, "part": 2, "q": "What time can I pick up my glasses?", "qko": "제 안경을 몇 시에 가져갈 수 있나요?", "opts": ["No, it's not very heavy.", "About twenty meters.", "We close at six o'clock."], "optko": ["아니요, 그렇게 무겁지 않습니다.", "약 20미터요.", "저희는 6시에 문을 닫습니다."], "ans": 2, "audio": "Test_01-13.mp3"}, {"n": 14, "part": 2, "q": "The sales team knows how to use the tracking software, don't they?", "qko": "영업팀이 추적 소프트웨어 이용법을 알죠, 그렇지 않나요?", "opts": ["It's on the lower shelf.", "A twelve-thirty departure.", "I haven't seen them using it yet."], "optko": ["그건 아래쪽 선반에 있어요.", "12시 30분 출발입니다.", "그분들이 그걸 이용하는 걸 아직 본 적이 없어요."], "ans": 2, "audio": "Test_01-14.mp3"}, {"n": 15, "part": 2, "q": "Are you going to the hardware store on Mill Street?", "qko": "밀 가에 있는 철물점에 가시는 건가요?", "opts": ["That store hasn't opened yet.", "The blue package you sent me.", "Some nails and a hammer."], "optko": ["그 매장은 아직 열지 않았어요.", "당신이 제게 보낸 파란색 소포요.", "못 몇 개와 망치요."], "ans": 0, "audio": "Test_01-15.mp3"}, {"n": 16, "part": 2, "q": "Would you be able to write the introduction for the workshop?", "qko": "워크숍 소개를 작성해 주실 수 있으신가요?", "opts": ["That was a great book.", "OK, I'd be happy to.", "He doesn't have any more."], "optko": ["그건 훌륭한 책이었어요.", "좋아요, 기꺼이 하겠습니다.", "그는 더 이상 갖고 있지 않아요."], "ans": 1, "audio": "Test_01-16.mp3"}, {"n": 17, "part": 2, "q": "I picked up some flowers for Tunji's retirement party.", "qko": "제가 툰지의 은퇴 파티를 위해 꽃을 좀 사왔습니다.", "opts": ["No, pick any day.", "That was thoughtful.", "A delivery driver."], "optko": ["아니요, 아무 날이나 고르세요.", "사려 깊으시네요.", "배송 기사님이요."], "ans": 1, "audio": "Test_01-17.mp3"}, {"n": 18, "part": 2, "q": "Which meeting room did you tell the interns to go to?", "qko": "인턴들에게 어느 회의실로 가라고 얘기하셨어요?", "opts": ["The Jefferson Room.", "The meeting was fun, thanks.", "Yes, it's a conference call."], "optko": ["제퍼슨 룸이요.", "회의가 재미있었어요, 감사합니다.", "네, 전화 회의입니다."], "ans": 0, "audio": "Test_01-18.mp3"}, {"n": 19, "part": 2, "q": "Is your dental appointment next Tuesday?", "qko": "당신 치과 예약이 다음 주 화요일인가요?", "opts": ["You can borrow mine.", "I'll have to check my calendar.", "Yes, it was a good meeting."], "optko": ["제 것을 빌리셔도 됩니다.", "제 일정표를 확인해 봐야 해요.", "네, 좋은 회의였어요."], "ans": 1, "audio": "Test_01-19.mp3"}, {"n": 20, "part": 2, "q": "Why aren't there any brochures in the lobby?", "qko": "왜 로비에 안내 책자가 하나도 없는 거죠?", "opts": ["No, I haven't received my confirmation e-mail yet.", "My winter coat.", "Because someone just took the last one."], "optko": ["아니요, 저는 아직 확인 이메일을 받지 못했어요.", "제 겨울 코트요.", "누군가 방금 마지막 것을 가져갔기 때문입니다."], "ans": 2, "audio": "Test_01-20.mp3"}, {"n": 21, "part": 2, "q": "What's the process for submitting my expense report?", "qko": "지출 보고서를 제출하는 절차가 어떻게 되죠?", "opts": ["You send it to the finance department.", "The end of the day.", "That's correct."], "optko": ["재무팀에 보내세요.", "하루 일과가 끝날 때요.", "맞습니다."], "ans": 0, "audio": "Test_01-21.mp3"}, {"n": 22, "part": 2, "q": "Do you sell your products online or in stores?", "qko": "제품을 온라인으로 판매하시나요, 아니면 매장에서 판매하시나요?", "opts": ["About twenty percent off.", "A product demonstration.", "Only online."], "optko": ["약 20퍼센트 할인이요.", "제품 시연회요.", "온라인으로만요."], "ans": 2, "audio": "Test_01-22.mp3"}, {"n": 23, "part": 2, "q": "How often do you charge this device?", "qko": "이 기기를 얼마나 자주 충전하세요?", "opts": ["Whenever the light turns red.", "A wireless one.", "At the hardware store."], "optko": ["표시등이 빨간색으로 바뀔 때마다요.", "무선 제품이요.", "철물점에서요."], "ans": 0, "audio": "Test_01-23.mp3"}, {"n": 24, "part": 2, "q": "The tickets to Friday night's concert cost ten dollars each.", "qko": "금요일 밤 콘서트 입장권은 각각 10달러입니다.", "opts": ["Actually, they're fifteen.", "No, I can't play the guitar.", "It's in aisle five."], "optko": ["실은, 15달러입니다.", "아니요, 저는 기타 칠 줄 몰라요.", "5번 통로에 있어요."], "ans": 0, "audio": "Test_01-24.mp3"}, {"n": 25, "part": 2, "q": "Can't you update the database today?", "qko": "오늘 데이터베이스를 업데이트할 수 없으신가요?", "opts": ["I did it yesterday.", "That's an interesting movie.", "No, just me."], "optko": ["어제 했습니다.", "흥미로운 영화네요.", "아니요, 저만요."], "ans": 0, "audio": "Test_01-25.mp3"}, {"n": 26, "part": 2, "q": "How are we going to fit the extra supplies in that closet?", "qko": "추가 물품을 저 수납장에 어떻게 넣을까요?", "opts": ["I've already read them.", "Natalie's in charge of supplies.", "It's the door at the end of the hallway."], "optko": ["저는 이미 그것들을 읽었습니다.", "나탈리가 물품을 담당해요.", "복도 끝에 있는 문이요."], "ans": 1, "audio": "Test_01-26.mp3"}, {"n": 27, "part": 2, "q": "Have all the new windows been installed?", "qko": "새 창문이 모두 설치되었나요?", "opts": ["Sure, I'll close the blinds.", "The construction crew is almost finished.", "This isn't the tallest ladder available."], "optko": ["물론이죠, 제가 블라인드를 닫을게요.", "공사 작업팀이 일을 거의 끝마쳤습니다.", "이것은 이용 가능한 가장 높은 사다리가 아닙니다."], "ans": 1, "audio": "Test_01-27.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "audio": "Test_01-32-34.mp3", "qs": [{"n": 32, "q": "What type of food product does the speakers' company sell?", "opts": ["Candy", "Cheese", "Bread", "Pasta"], "ans": 1, "ko": "전체 내용 관련 - 화자들의 회사가 판매하는 식품. 여자가 첫 대사에서 '우리의 새 매운 체다 치즈(our new spicy cheddar cheese)'라고 말하고 있으므로 정답은 (B)이다."}, {"n": 33, "q": "What does the man suggest?", "opts": ["Lowering prices", "Hiring more workers", "Publishing a recipe", "Offering additional options"], "ans": 3, "ko": "세부 사항 관련 - 남자의 제안 사항. 남자가 두 번째 대사에서 조리 시에 쉽게 녹을 수 있는 잘게 조각난 버전을 판매하는 걸 고려해 보는 게 좋겠다(So maybe we should consider selling a shredded version that would melt easily when cooked)고 제안하고 있다. 이는 다른 옵션을 추가하는 뜻이므로 정답은 (D)이다."}, {"n": 34, "q": "What does the woman say she will do?", "opts": ["Send a schedule update", "Contact a production manager", "Visit the company headquarters", "Plan an advertising campaign"], "ans": 2, "ko": "세부 사항 관련 - 여자가 할 일. 여자가 마지막 대사에서 생산 관리자에게 연락해 그 요청 사항을 전달하겠다(I'll get in touch with the production manager with that request)고 했으므로 정답은 (B)이다."}], "script": [{"sp": "W", "en": "Hey, Oliver. Did you see the focus group results for our new spicy cheddar cheese? Everyone really liked it.", "ko": "안녕하세요, 올리버. 우리의 새 매운 체다 치즈에 대한 포커스 그룹 결과를 보셨나요? 모든 분이 정말로 좋아하셨어요."}, {"sp": "M", "en": "Yes. It should be a great addition to our company's line of cheeses.", "ko": "네. 우리 회사의 치즈 제품 라인에 훌륭한 추가 제품이 될 겁니다."}, {"sp": "W", "en": "Several people mentioned that they'd like to use it in recipes—to add to sauces, for example.", "ko": "여러 사람이 그것을 요리에 사용하고 싶다고 언급했어요. 예를 들면 소스에 넣는 거죠."}, {"sp": "M", "en": "So maybe we should consider selling a shredded version that would melt easily when cooked.", "ko": "그래서 아마도 우리는 조리할 때 쉽게 녹는 잘게 썬 버전을 판매하는 것을 고려해야 할 것 같아요."}, {"sp": "W", "en": "I'm sure we could do that. I'll get in touch with the production manager with that request.", "ko": "충분히 할 수 있을 거예요. 제가 그 요청 사항을 가지고 생산 관리자에게 연락할게요."}, {"sp": "W", "en": "You mentioned that many people would like to use it in recipes. For example, adding it to sauces.", "ko": "여러 사람들이 조리법에 사용하고 싶다고 언급하셨어요. 예를 들면, 소스에 추가하는 것이죠."}, {"sp": "M", "en": "So maybe we should consider selling a shredded version that would melt easily when cooked.", "ko": "그럼 조리 시에 쉽게 녹을 수 있는 잘게 조각난 버전을 판매하는 걸 고려해 보는 게 좋겠어요."}, {"sp": "W", "en": "We can certainly do that. I'll get in touch with the production manager with that request.", "ko": "분명 그렇게 할 수 있을 거예요. 제가 생산 관리자에게 연락해 그 요청 사항을 전달할게요."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "audio": "Test_01-35-37.mp3", "qs": [{"n": 35, "q": "Why is the man calling?", "opts": ["To sign up for lessons", "To enter a competition", "To buy tickets to an event", "To ask about branded merchandise"], "ans": 2, "ko": "남자가 첫 대사에서 이번 주 목요일에 있을 테니스 경기 입장권을 세 매 예매하려고 전화했다(I'm calling to book three tickets for this Thursday's tennis match)고 했으므로 정답은 (C)."}, {"n": 36, "q": "What did Ife Rotimi do last month?", "opts": ["She won a regional tournament.", "She gave a television interview.", "She started an institute.", "She hired a new coach."], "ans": 2, "ko": "남자가 두 번째 대사에서 이페 로티미가 지난달에 지역 선수권 대회에서 우승했다(Ife Rotimi won the regional championship tournament last month)고 했으므로 정답은 (A)."}, {"n": 37, "q": "What does the woman say is required?", "opts": ["A parking permit", "A photo ID", "Contact information", "Advance payment"], "ans": 3, "ko": "여자가 마지막 대사에서 자리를 맡으려면 사전 결제가 필요하다(Advance payment is required to hold them)고 했으므로 정답은 (D)."}], "script": [{"sp": "M", "en": "Hi. I'm calling to book three tickets for this Thursday's tennis match. Are there any seats left?", "ko": "안녕하세요. 이번 주 목요일에 있을 테니스 경기 입장권을 세 매 예매하려고 전화했어요. 좌석이 남아 있나요?"}, {"sp": "W", "en": "Just a few! Tickets for Thursday's match have been selling quickly.", "ko": "겨우 몇 개만 있어요! 목요일 경기 입장권이 빠르게 판매되고 있거든요."}, {"sp": "M", "en": "I'm not surprised! After all, Ife Rotimi won the regional championship tournament last month. Everyone wants to see her play after her incredible performance. What seats are available?", "ko": "놀랍지 않네요! 어쨌든, 이페 로티미가 지난달에 지역 선수권 대회에서 우승했잖아요. 놀라운 성적을 거둔 후로 모두 그녀가 경기하는 것을 보고 싶어 하니까요. 어떤 좌석을 이용할 수 있나요?"}, {"sp": "W", "en": "Well, there's only one group of three seats together. Advance payment is required to hold them.", "ko": "흠, 세 개의 좌석이 붙어 있는 건 하나뿐이네요. 이 자리를 맡으시려면 사전 결제가 필요합니다."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "audio": "Test_01-38-40.mp3", "qs": [{"n": 38, "q": "What event are the speakers planning?", "opts": ["A fund-raising dinner", "An art gallery opening", "An awards ceremony", "A children's book fair"], "ans": 1, "ko": "여자가 첫 대사에서 남자에게 도서관의 연례 기금 마련 만찬 준비를 도와주기로 동의해 줘서 고맙다(Thanks for agreeing to help me organize the library's annual fund-raising dinner, Klaus)고 했으므로 정답은 (A)."}, {"n": 39, "q": "What task does the woman ask the man to help with?", "opts": ["Arranging a shuttle service", "Choosing a catering firm", "Preparing a speech", "Sending out invitations"], "ans": 3, "ko": "세부 사항 관련 - 여자의 요청 사항. 여자가 두 번째 대사에서 초대장 발송을 도와주면 좋겠다(Well, I could use some help sending out the invitations)고 했으므로 정답은 (D)이다."}, {"n": 40, "q": "What does the woman say she will do?", "opts": ["E-mail a list", "Speak with a colleague", "Provide a password", "Post a job opening"], "ans": 0, "ko": "세부 사항 관련 - 여자가 할 일. 남자가 두 번째 대사에서 이용 가능한 참석자 명단이 있는지(Is there a list of attendees available?) 묻자, 여자가 그것을 이메일로 보내 주겠다(I'll e-mail it to you)고 응답하고 있으므로 정답은 (A)이다."}], "script": [{"sp": "W", "en": "Thanks for agreeing to help me organize the library's annual fund-raising dinner, Klaus. We hope the event brings in enough money to expand our children's book section.", "ko": "도서관의 연례 기금 마련 만찬 준비를 도와주시기로 동의해 주셔서 감사합니다, 클라우스. 이 행사를 통해 아동 도서 섹션을 확장할 수 있는 충분한 돈이 마련되기를 바랍니다."}, {"sp": "M", "en": "What task would you like me to start with?", "ko": "제가 어떤 일부터 시작하면 될까요?"}, {"sp": "W", "en": "Well, I could use some help sending out the invitations.", "ko": "음, 초대장 발송을 도와주시면 좋겠습니다."}, {"sp": "M", "en": "OK, I can take care of that. Is there a list of attendees available?", "ko": "알겠습니다, 제가 처리할 수 있습니다. 이용 가능한 참석자 명단이 있나요?"}, {"sp": "W", "en": "It's in my computer files. I'll e-mail it to you.", "ko": "제 컴퓨터 파일에 있습니다. 이메일로 보내 드릴게요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "audio": "Test_01-41-43.mp3", "qs": [{"n": 41, "q": "What event are the speakers preparing for?", "opts": ["A new-employee orientation", "A grand opening", "A community festival", "A trade show"], "ans": 2, "ko": "전체 내용 관련 - 화자들이 준비하는 행사. 여자가 첫 대사에서 지역 축제에서 업체 홍보용으로 나눠 주기 좋은 펜을 몇 개 발견했다(I found some great pens to give away at the community festival to promote our business)고 했으므로 정답은 (C)이다."}, {"n": 42, "q": "What is mentioned about some pens?", "opts": ["They are available in multiple colors.", "They use permanent ink.", "They are preferred by book authors.", "They are made from paper."], "ans": 3, "ko": "세부 사항 관련 - 펜과 관련해 언급되는 것. 여자가 두 번째 대사에서 펜들이 종이로 만들어진다(They're made from paper)고 했으므로 정답은 (D)이다."}, {"n": 43, "q": "What does the woman offer to do?", "opts": ["Reserve a booth", "Place an order", "Organize a focus group", "Revise a budget"], "ans": 1, "ko": "여자가 마지막 대사에서 바로 여러 케이스 주문하겠다(I'll go ahead and order several cases)고 했으므로 정답은 (B)이다."}], "script": [{"sp": "W", "en": "Hey, Brian and Matteo. I found some great pens to give away at the community festival to promote our business.", "ko": "안녕하세요, 브라이언, 마테오. 제가 지역 축제에서 업체 홍보용으로 나눠 주기 좋은 펜을 몇 개 발견했어요."}, {"sp": "M1", "en": "Great. Can we put our cleaning service logo on them?", "ko": "잘됐네요. 거기에 우리 청소 서비스 로고를 넣을 수 있나요?"}, {"sp": "W", "en": "Yes, for no extra charge. And they're biodegradable. They're made from paper.", "ko": "네, 추가 요금 없이요. 그리고 생분해성이에요. 종이로 만들어지거든요."}, {"sp": "M2", "en": "So when we hand them out, we can mention that.", "ko": "그럼 우리가 그걸 나눠 줄 때, 그 부분을 언급할 수 있겠네요."}, {"sp": "M1", "en": "As well as talk about the organic cleaning supplies our company uses.", "ko": "우리 회사가 이용하는 유기농 청소 용품에 관해서도 이야기하고요."}, {"sp": "W", "en": "OK. I'll go ahead and order several cases.", "ko": "좋습니다. 그럼 제가 바로 여러 케이스 주문할게요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "audio": "Test_01-44-46.mp3", "qs": [{"n": 44, "q": "Where does the woman work?", "opts": ["At a delivery service", "At an electronics store", "At a recycling facility", "At a real estate agency"], "ans": 2, "ko": "여자가 첫 대사에서 제임스타운 재활용 시설(Jamestown Recycling Facility)이라고 자신이 근무하는 곳을 밝히고 있으므로 정답은 (C)이다."}, {"n": 45, "q": "What does the man want to dispose of?", "opts": ["Yard waste", "Used furniture", "Electronics", "Books"], "ans": 2, "ko": "남자가 첫 대사에서 집을 내놓기 전에 치우고 싶은 텔레비전과 컴퓨터 같은 전자 제품들이 있다고 했으므로 정답은 (C)이다."}, {"n": 46, "q": "What does the woman say can be found on a Web site?", "opts": ["A list of companies", "Hours of operation", "A permit application", "Directions to a site"], "ans": 0, "ko": "여자가 웹사이트에 물품들을 대신 치우고 처리해 줄 수 있는 많은 회사들의 목록이 있다고 했으므로 정답은 (A)이다."}], "script": [{"sp": "W", "en": "Jamestown Recycling Facility. How can I help you?", "ko": "제임스타운 재활용 시설입니다. 무엇을 도와드릴까요?"}, {"sp": "M", "en": "Hi. I'm preparing to move soon, and I have some electronics, such as televisions and computers, that I'd like to get rid of before I put my house on the market. My friend mentioned you might take them.", "ko": "안녕하세요. 제가 곧 이사할 준비를 하고 있는데, 집을 내놓기 전에 치우고 싶은 텔레비전과 컴퓨터 같은 전자 제품들이 있습니다. 제 친구가 그쪽에서 가져갈지도 모른다고 말해 주었어요."}, {"sp": "W", "en": "Yes, that's right. We'll take all electronics.", "ko": "네, 그렇습니다. 저희는 모든 전자 제품을 받습니다."}, {"sp": "M", "en": "Great. I just have one question. Do you provide a pickup service?", "ko": "잘됐네요. 질문이 하나 있습니다. 수거 서비스도 제공하시나요?"}, {"sp": "W", "en": "No, unfortunately you'll have to bring everything here yourself. However, on our Web site we list a number of companies that can remove and dispose of the items for you.", "ko": "아니요, 유감스럽게도 모든 것을 이곳으로 직접 가져오셔야 합니다. 하지만 저희 웹사이트에 물품들을 대신 치우고 처리해 줄 수 있는 많은 회사들의 목록이 있습니다."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "audio": "Test_01-47-49.mp3", "qs": [{"n": 47, "q": "How do the speakers know each other?", "opts": ["They took a class together.", "They used to work for the same company.", "They grew up in the same neighborhood.", "They met on a train."], "ans": 0, "ko": "세부 사항 관련 - 화자들이 서로 알게 된 계기. 남자가 첫 대사에서 작년에 업체 소유주들을 위한 수업을 함께 들은 이후로 만나지 못했다(I haven't seen you since we took that class for business owners together last year)고 했으므로 정답은 (A)이다."}, {"n": 48, "q": "What type of business does the man most likely own?", "opts": ["A fitness center", "A real estate agency", "A culinary school", "A bakery"], "ans": 3, "ko": "세부 사항 관련 - 남자가 소유한 업체. 여자가 첫 대사에서 쿠키나 케이크 한 조각 먹으러 들러야겠다고 생각했다는 말과 함께 남자의 업체에 맛있는 제과제품이 아주 많다(~ thought I'd stop in for a cookie or a piece of cake. You have so many delicious baked goods here)고 했으므로 정답은 (D)이다."}, {"n": 49, "q": "What advantage does the woman point out about a rental space?", "opts": ["Its price", "Its size", "Its location", "Its design"], "ans": 2, "ko": "세부 사항 관련 - 여자가 언급하는 임대 공간의 장점. 여자가 마지막 대사에서 임대 가능한 공간에 대해 이야기하면서 지역 대학교와 아주 가깝다(It's very close to the local university)고 했으므로 정답은 (C)이다."}], "script": [{"sp": "M", "en": "Zaina! What a surprise! I haven't seen you since we took that class for business owners together last year. How are you?", "ko": "재이나! 놀랍네요! 작년에 업체 소유주들을 위한 수업을 함께 들은 이후로 만나지 못했잖아요. 어떻게 지내세요?"}, {"sp": "W", "en": "Great, thanks. I was just in the neighborhood and thought I'd stop in for a cookie or a piece of cake. You have so many delicious baked goods here.", "ko": "잘 지내고 있어요, 감사합니다. 이 지역에 막 와서 쿠키나 케이크 한 조각 먹으러 들러야겠다고 생각했거든요. 여기 맛있는 제과제품이 아주 많네요."}, {"sp": "M", "en": "Thank you! It's been a good year for business. I'm even considering opening a second location.", "ko": "감사합니다! 올해 사업이 잘되고 있어요. 심지어 2호점 개장을 고려하고 있습니다."}, {"sp": "W", "en": "Really? Well, I noticed that Sunnyvale Restaurant went out of business, and the building's up for lease. It's very close to the local university. You'd probably get a lot of walk-in customers.", "ko": "정말인가요? 음, 써니베일 레스토랑이 폐업해서 그 건물이 임대 매물로 나온 것을 봤어요. 지역 대학교와 아주 가까워요. 아마 지나가다 들르는 고객이 많을 거예요."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "audio": "Test_01-50-52.mp3", "qs": [{"n": 50, "q": "Who most likely are the speakers?", "opts": ["Film actors", "Museum directors", "Video game developers", "Investigative journalists"], "ans": 2, "ko": "여자가 첫 대사에서 신작 비디오 게임 출시 준비가 거의 다 된 것 같다(I think our new video game is nearly ready to be released)고 했으므로 정답은 (C)이다."}, {"n": 51, "q": "What did the man recently do?", "opts": ["He secured some funding.", "He tested a product.", "He read a script.", "He conducted an interview."], "ans": 1, "ko": "남자가 첫 대사에서 오늘 아침에 막 그 게임 테스트 작업을 마쳤다(I just finished testing the game this morning)고 했으므로 정답은 (B)이다."}, {"n": 52, "q": "What does the woman suggest?", "opts": ["Consulting a colleague", "Planning an event", "Negotiating a contract", "Giving a client an update"], "ans": 0, "ko": "여자가 마지막 대사에서 폴린도 테스트했던 게임에서 유사한 문제를 겪었던 것 같다며 그 부분에 대해 그녀에게 물어보는 게 좋겠다(I think Pauline had a similar problem with a game she tested. Maybe you should ask her about it)고 했으므로 정답은 (A)이다."}], "script": [{"sp": "W", "en": "Hi, Koji. I think our new video game is nearly ready to be released. Are you aware of any improvements that need to be made before then?", "ko": "안녕하세요, 코지. 우리 신작 비디오 게임 출시 준비가 거의 다 된 것 같아요. 그 전에 개선되어야 할 점이 있는지 알고 계신 게 있을까요?"}, {"sp": "M", "en": "Actually, I just finished testing the game this morning. I found a problem in the third stage of the game. There were a few times when my character couldn't move.", "ko": "실은, 제가 오늘 아침에 막 그 게임 테스트 작업을 마쳤습니다. 게임의 세 번째 단계에서 문제를 하나 발견했어요. 제 캐릭터를 움직일 수 없었던 적이 여러 번 있었어요."}, {"sp": "W", "en": "Oh, that's strange!", "ko": "아, 그거 이상하네요!"}, {"sp": "M", "en": "I double-checked the problem using a different controller. The same issue came up.", "ko": "제가 다른 조종기를 이용해서 이 문제를 이중으로 점검했습니다. 그런데 같은 문제가 발생했어요."}, {"sp": "W", "en": "Oh. I think Pauline had a similar problem with a game she tested. Maybe you should ask her about it.", "ko": "오. 폴린도 테스트했던 게임에서 유사한 문제를 겪었던 것 같아요. 그 부분에 대해 그녀에게 물어보는 게 좋겠어요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "audio": "Test_01-53-55.mp3", "qs": [{"n": 53, "q": "Who most likely is the man?", "opts": ["A delivery driver", "A security guard", "A maintenance worker", "A customer service representative"], "ans": 2, "ko": "전체 내용 관련 - 남자의 직업. 남자가 첫 대사에서 힐뷰 아파트 단지 관리소(You've reached the maintenance office at Hillview Apartment Complex)라고 말한 것에서 관리소 직원임을 알 수 있으므로 정답은 (C)이다."}, {"n": 54, "q": "What problem does the woman describe?", "opts": ["A device is malfunctioning.", "A key is missing.", "A parking area is unavailable.", "A package was not received."], "ans": 0, "ko": "전체 내용 관련 - 여자가 설명하는 문제. 여자가 첫 대사에서 아파트의 새 온도 조절 장치가 작동하지 않아서 전화했다며 계속 무작위로 꺼졌다가 켜진다(I'm calling because the new thermostat in my apartment isn't working. It keeps shutting off and turning on randomly ~)고 했으므로 정답은 (A)이다."}, {"n": 55, "q": "What does the woman mean when she says, \"it's supposed to be below freezing tonight\"?", "opts": ["She is surprised by the weather forecast.", "She wants a service to be completed sooner.", "She will move some items indoors.", "She would prefer to park near her apartment."], "ans": 1, "ko": "화자의 의도 파악 - 오늘 밤에 영하로 떨어질 것이라는 말의 의미. 남자가 세 번째 대사에서 자신이 내일 오전에 가서 봐 줄 수 있다(I can come and take a look at it tomorrow morning)고 말하자, 여자가 인용문을 언급하고 있다. 이는 오늘 밤에 날씨가 추우니 내일 아침보다 더 빨리 와서 봐 주길 원한다는 뜻이므로 정답은 (B)이다."}], "script": [{"sp": "M", "en": "You've reached the maintenance office at Hillview Apartment Complex.", "ko": "힐뷰 아파트 단지 관리소입니다."}, {"sp": "W", "en": "Hi. This is Palavi Sen from unit 35B. I'm calling because the new thermostat in my apartment isn't working. It keeps shutting off and turning on randomly, so my apartment is getting cold.", "ko": "안녕하세요. 저는 35B호에 사는 팔라비 센입니다. 제 아파트의 새 온도 조절 장치가 작동하지 않아서 전화했어요. 계속 무작위로 꺼졌다 켜졌다 해서, 아파트가 추워지고 있어요."}, {"sp": "M", "en": "When did this issue start?", "ko": "그 문제가 언제 시작되었나요?"}, {"sp": "W", "en": "A few hours ago. The thermostat was just installed yesterday.", "ko": "몇 시간 전에요. 온도 조절 장치는 어제 막 설치했어요."}, {"sp": "M", "en": "OK. I can come and take a look at it tomorrow morning.", "ko": "알겠습니다. 제가 내일 오전에 가서 봐 드릴 수 있습니다."}, {"sp": "W", "en": "But it's supposed to be below freezing tonight!", "ko": "하지만 오늘 밤에 영하로 떨어질 거예요!"}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "audio": "Test_01-56-58.mp3", "qs": [{"n": 56, "q": "Why do the men want to speak to the woman?", "opts": ["To review a building design", "To discuss a loan", "To develop an advertising plan", "To purchase some supplies"], "ans": 1, "ko": "전체 내용 관련 - 첫 번째 남자가 첫 대사에서 사업 자금 대출을 논의하기 위해 만나 줘서 감사하다(Thanks for meeting with us to discuss a loan for our business)고 했으므로 정답은 (B)이다."}, {"n": 57, "q": "What type of business do the men own?", "opts": ["A sports equipment store", "A winter apparel store", "An automobile dealership", "A hotel chain"], "ans": 0, "ko": "전체 내용 관련 - 두 번째 남자가 첫 대사에서 자신들의 업체가 수리점이면서 스노모빌과 기타 스포츠 장비 대여도 시작했다(~ we also started renting out snowmobiles and other sports equipment)고 했으므로 정답은 (A)이다."}, {"n": 58, "q": "According to the men, what has changed recently?", "opts": ["Roads have become more accessible.", "Costs have decreased.", "Tourism has increased.", "Weather patterns have shifted."], "ans": 2, "ko": "세부 사항 관련 - 첫 번째 남자가 마지막 대사에서 최근 겨울철 관광 산업이 증가했다(~ winter tourism has increased recently ~)고 했으므로 정답은 (C)이다."}], "script": [{"sp": "W", "en": "Good morning! Welcome to Jasper Bank.", "ko": "안녕하세요! 재스퍼 은행에 오신 것을 환영합니다."}, {"sp": "M1", "en": "Thanks for meeting with us to discuss a loan for our business.", "ko": "사업 자금 대출을 논의하기 위해 만나 주셔서 감사합니다."}, {"sp": "W", "en": "Why don't you tell me more about your business? I understand it's a repair shop?", "ko": "두 분의 업체에 대해 더 말씀해 주시겠어요? 수리점이라고 알고 있는데요?"}, {"sp": "M2", "en": "Well, ten years ago, we opened as a snowmobile repair shop, but after a few years, we also started renting out snowmobiles and other sports equipment.", "ko": "음, 10년 전에, 저희는 스노모빌 수리점으로 문을 열었는데, 몇 년 후에는, 스노모빌과 기타 스포츠 장비 대여도 시작했습니다."}, {"sp": "M1", "en": "Yes, and because winter tourism has increased recently, we'd like to expand our space so that we can carry more inventory.", "ko": "네, 그리고 최근 겨울철 관광 산업이 증가해서, 더 많은 재고를 취급할 수 있도록 공간을 확장하고자 합니다."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "audio": "Test_01-59-61.mp3", "qs": [{"n": 59, "q": "What does the man want to do?", "opts": ["Provide training opportunities", "Upgrade machinery", "Hire additional employees", "Reorganize the factory layout"], "ans": 0, "ko": "남자가 첫 대사에서 동료 교육 프로그램을 시행하고 싶다며, 배우는 사람들이 경험 많은 직원을 따라다니며 관찰하는 것(implement a peer-training program)이라고 했으므로 정답은 (A) 교육 기회 제공하기."}, {"n": 60, "q": "What is the woman concerned about?", "opts": ["Increasing expenses", "Introducing errors", "Reducing productivity", "Causing confusion"], "ans": 2, "ko": "여자가 장기 재직 직원들에게 부담이 될까 걱정이며, 설명을 위해 업무 속도를 늦춰야 할 것(slow down their work)이라고 했으므로, 이는 생산성 감소에 해당해 정답은 (C) Reducing productivity."}, {"n": 61, "q": "What does the man mean when he says, \"High-quality video can be recorded and edited with a smartphone\"?", "opts": ["A new policy should be established.", "An idea is easy to implement.", "Data security is a concern.", "Some information should be verified."], "ans": 1, "ko": "남자가 경험 많은 직원들이 특정 업무를 하는 모습을 영상으로 녹화하자고 제안하면서 스마트폰으로 쉽게 녹화·편집할 수 있다고 인용했으므로, 아이디어 시행이 쉽다는 의미로 정답은 (B) An idea is easy to implement."}], "script": [{"sp": "M", "en": "Many of our factory workers have expressed interest in upgrading their skills. I'd like to implement a peer-training program, where learners shadow more-experienced employees and observe how they do their jobs.", "ko": "저희 공장 직원들 중 많은 이들이 자신의 기술을 향상시키는 데 관심을 표현했습니다. 저는 학습자들이 더 경험이 많은 직원들을 따라다니며 그들이 어떻게 일하는지 관찰하는 동료 교육 프로그램을 시행하고 싶습니다."}, {"sp": "W", "en": "I'm afraid that might become a burden for our long-time employees. They'll have to slow down their work to explain what they're doing.", "ko": "그것이 저희 오래 근무한 직원들에게 부담이 될까 봐 걱정됩니다. 그들은 자신이 하는 일을 설명하기 위해 작업 속도를 늦춰야 할 것입니다."}, {"sp": "M", "en": "What if we videotaped experienced employees doing specific tasks? High-quality video can be recorded and edited with a smartphone.", "ko": "숙련된 직원들이 특정 작업을 하는 것을 녹화하면 어떨까요? 고품질 영상은 스마트폰으로 녹화하고 편집할 수 있습니다."}, {"sp": "W", "en": "I like that idea. It would allow us to capture our workers' expertise without slowing down the production line.", "ko": "그 아이디어가 마음에 드네요. 그러면 생산 라인을 늦추지 않고도 직원들의 전문 지식을 담아낼 수 있을 거예요."}, {"sp": "M", "en": "Many of our factory workers have expressed interest in upgrading their skills. I'd like to implement a peer-training program, where learners shadow more-experienced employees and observe how they do their jobs.", "ko": "우리 공장 직원들 중 많은 분들이 자신의 능력을 업그레이드하는 데 관심을 보이셨습니다. 동료 교육 프로그램을 시행했으면 하는데, 배우는 사람들이 경험이 더 많은 직원들을 그림자처럼 따라다니면서 어떻게 일하는지 관찰하는 겁니다."}, {"sp": "W", "en": "I'm concerned that could be a burden on our long-time employees. They'll have to slow down their work to explain what they're doing.", "ko": "저는 그게 오랫동안 근무한 직원들에게 부담이 될 수 있을 것 같아서 걱정이에요. 무엇을 하고 있는지 설명하기 위해 업무 속도를 늦춰야 할 겁니다."}, {"sp": "M", "en": "What if we videotaped experienced employees doing specific tasks? High-quality video can be recorded and edited with a smartphone.", "ko": "경험 많은 직원들이 특정 업무를 하는 모습을 영상으로 녹화하면 어떨까요? 스마트폰으로 고품질의 영상을 녹화하고 편집할 수 있어요."}, {"sp": "W", "en": "I like that idea. We could capture our employees' expertise without slowing down the production line.", "ko": "그 아이디어가 좋네요. 생산 라인의 속도를 늦추지 않고 우리 직원들의 전문 기술을 담을 수 있을 거예요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "audio": "Test_01-62-64.mp3", "qs": [{"n": 62, "q": "Where is the woman?", "opts": ["At a restaurant", "At a travel agency", "At an airport", "At a warehouse"], "ans": 2, "ko": "여자가 첫 대사에서 공항에서 비행기를 기다리고 있다(I'm at the airport waiting for my flight)고 했으므로 정답은 (C)이다."}, {"n": 63, "q": "Look at the graphic. When does the woman prefer to meet with an investor?", "opts": ["On Monday", "On Tuesday", "On Wednesday", "On Thursday"], "ans": 2, "ko": "남자가 첫 대사에서 투자자를 어느 요일에 만나고 싶은지(Which day would you prefer to meet with her?) 묻자, 여자가 시카고 직원들과의 회의 직후(How about right after my meeting with the Chicago staff?)를 제안하고 있다. 일정표에서 시카고 직원들과의 회의가 수요일인 것을 알 수 있으므로 정답은 (C)이다."}, {"n": 64, "q": "What good news does the man share?", "opts": ["A colleague received a promotion.", "A conference proposal was accepted.", "An airline ticket has been upgraded.", "A company won an award."], "ans": 3, "ko": "남자가 마지막 대사에서 여자에게 소속 회사가 지역 사회에 기여한 공로를 인정받아 상을 받은 것을 봤는지(~ did you see that our company won an award for our contributions to the community?) 물으며, 오늘 아침에 발표됐다고 했으므로 정답은 (D)이다."}], "script": [{"sp": "W", "en": "Hi, Suresh. I'm at the airport waiting for my flight. I want to meet with a potential investor while I'm in Chicago. Her name's Marta Gomez. I can send you her contact information.", "ko": "안녕하세요, Suresh. 저는 공항에서 비행기를 기다리고 있어요. Chicago에 있는 동안 잠재 투자자와 만나고 싶어요. 그녀의 이름은 Marta Gomez예요. 그녀의 연락처를 보내드릴 수 있어요."}, {"sp": "M", "en": "OK. Which day would you prefer to meet with her?", "ko": "알겠어요. 그녀와 어느 날 만나는 게 좋으시겠어요?"}, {"sp": "W", "en": "How about right after my meeting with the Chicago staff?", "ko": "시카고 직원들과의 회의 직후가 어떨까요?"}, {"sp": "M", "en": "OK. By the way, did you see that our company won an award for our contributions to the community? It was just announced this morning.", "ko": "좋습니다. 그건 그렇고, 우리 회사가 지역 사회에 기여한 공로를 인정받아 상을 받은 것을 보셨나요? 오늘 아침에 막 발표되었어요."}], "gimg": "ets_t1_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "audio": "Test_01-65-67.mp3", "qs": [{"n": 65, "q": "Where do the speakers work?", "opts": ["At an amusement park", "At an art museum", "At a concert hall", "At a botanical garden"], "ans": 3, "ko": "화자들의 근무 장소. 남자가 첫 대사에서 식물원 방문을 원하지만 주차 정보를 찾지 못하는 사람들로부터 계속 전화를 받고 있다고 했으므로 정답은 (D) 식물원이다."}, {"n": 66, "q": "Look at the graphic. Which page on the Web site does the man want to change?", "opts": ["Page 1", "Page 2", "Page 3", "Page 4"], "ans": 0, "ko": "남자가 변경하려는 페이지. 그 정보를 \"소개\" 페이지에서 옮겨서 길 안내와 주차 정보를 위한 별도의 페이지를 만들 것을 제안하고 있고, 웹페이지 목록에서 소개 페이지는 1페이지이므로 정답은 (A) 1페이지이다."}, {"n": 67, "q": "Why does the woman say she cannot complete a task until Monday?", "opts": ["She requires approval from a manager.", "She is attending a workshop.", "Some software is being updated.", "Some clients will be arriving soon."], "ans": 2, "ko": "월요일까지 일을 완료할 수 없는 이유. 여자가 마지막 대사에서 소프트웨어를 업데이트하는 중이라 월요일까지 기다려야 한다고 했으므로 정답은 (C) 소프트웨어가 업데이트되고 있다이다."}], "script": [{"sp": "", "en": "separate page for directions and parking information. That way, people can find it more easily.", "ko": "그 정보를 \"소개\" 페이지에서 옮겨서 길 안내와 주차 정보를 위한 별도의 페이지를 만들어야 할 것 같아요. 그러면 사람들이 더 쉽게 찾을 수 있을 거예요."}, {"sp": "W", "en": "I'd be happy to make that change. But we're in the middle of updating our software, so it'll have to wait until Monday.", "ko": "제가 그렇게 변경하겠습니다. 하지만 소프트웨어를 업데이트하는 중이라, 월요일까지 기다려야 할 거예요."}], "gimg": "ets_t1_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "audio": "Test_01-68-70.mp3", "qs": [{"n": 68, "q": "What news does the man share?", "opts": ["A station road will be closed for repair.", "A project has been approved.", "A parking area has been expanded.", "An office will relocate."], "ans": 1, "ko": "남자가 첫 대사에서 시내 기차역에 자전거 거치대를 설치하는 부서 프로젝트가 드디어 승인을 받았다(We have finally received the go-ahead for our department's project...)고 소식을 공유하므로 정답은 (B) A project has been approved."}, {"n": 69, "q": "Look at the graphic. Where do the speakers decide to install some bicycle racks?", "opts": ["Near the covered parking area", "Near the long-term parking area", "Near the short-term parking area", "Near the overflow parking area"], "ans": 3, "ko": "남자가 승강장과 가장 가까운 곳이 편리하다고 하고(I bet they'd say that the most convenient spot is as close to the platform as possible) 여자도 동의(Let's do that). 역 안내도에서 승강장과 가장 가까운 곳은 지붕으로 덮인 주차장이므로 정답은 (A) Near the covered parking area."}, {"n": 70, "q": "Why does the woman say she will contact some companies?", "opts": ["To arrange a loan", "To apply for a permit", "To ask for estimates", "To create a proposal"], "ans": 2, "ko": ""}], "script": [{"sp": "M", "en": "Good news! We have finally received the go-ahead for our department's project to install bicycle racks at the train station downtown.", "ko": "좋은 소식입니다! 시내 기차역에 자전거 거치대를 설치하는 우리 부서의 프로젝트가 드디어 승인을 받았습니다."}, {"sp": "W", "en": "At last! So, now we need to decide where to place the racks. How about by the station entrance?", "ko": "마침내 됐네요! 그럼, 이제 우리는 거치대를 어디에 놓을지 결정해야 합니다. 역 입구 옆은 어떤가요?"}, {"sp": "M", "en": "Hmm. If we asked riders, I bet they'd say that the most convenient spot is as close to the platform as possible.", "ko": "흠. 우리가 자전거 이용객들에게 묻는다면, 틀림없이 가능한 한 승강장과 가까운 곳이 가장 편리한 자리라고 말할 겁니다."}, {"sp": "W", "en": "Let's do that. I'll contact some companies for estimates.", "ko": "그렇게 합시다. 제가 견적을 위해 몇몇 회사에 연락할게요."}], "gimg": "ets_t1_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "audio": "Test_01-71-73.mp3", "qs": [{"n": 71, "q": "What type of products does the business repair?", "opts": ["Computers", "Vehicles", "Light fixtures", "Kitchen appliances"], "ans": 1, "ko": "전체 내용 관련. 화자가 초반부에 모든 자동차 브랜드와 모델을 전문으로 다룬다(We specialize in all makes and models of automobiles)고 했으므로 정답은 (B). 담화의 automobiles → 정답의 Vehicles."}, {"n": 72, "q": "What special benefit does the speaker mention?", "opts": ["Free pickup", "Online scheduling", "Extended warranties", "A membership loyalty program"], "ans": 2, "ko": "세부 사항 관련. 화자가 중반부에 추가 혜택으로 정비하는 모든 차량에 연장된 품질 보증 서비스를 제공한다(As an added benefit, we offer extended warranties on all vehicles we service)고 했으므로 정답은 (C). 담화의 an added benefit → 질문의 special benefit."}, {"n": 73, "q": "Why will a business close on Friday?", "opts": ["For an inventory count", "For employee training", "For a company celebration", "For equipment installation"], "ans": 0, "ko": "세부 사항 관련. 분기별 재고 조사를 완료하기 위해 6월 30일 금요일에 문을 닫는다고 했으므로 정답은 (A) 재고 조사 때문에."}], "script": [{"sp": "W-Br", "en": "You've reached Select Repair Service. We specialize in all makes and models of automobiles. Our factory-trained specialists will keep your vehicle running in top condition. As an added benefit, we offer extended warranties on all vehicles we service. You can enjoy three extra years of worry-free driving. Please note that Select Repair Service will be closing on Friday, June 30, so we can complete our quarterly inventory of supplies. Thank you for your patience. A representative will be with you shortly.", "ko": "셀렉트 리페어 서비스입니다. 저희는 모든 자동차 브랜드와 모델을 전문으로 다룹니다. 공장에서 교육을 받은 저희 전문가들이 여러분의 차량을 최상의 상태로 운행할 수 있도록 관리해 드릴 것입니다. 추가 혜택으로 저희가 정비해 드리는 모든 차량에 연장된 품질 보증 서비스를 제공해 드립니다. 추가로 3년 동안 걱정 없이 운전하실 수 있습니다. 저희 셀렉트 리페어 서비스가 분기별 재고 조사를 완료하기 위해, 6월 30일 금요일에 문을 닫을 예정임을 알려 드립니다. 기다려 주셔서 감사합니다. 곧 직원이 연결될 것입니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "audio": "Test_01-74-76.mp3", "qs": [{"n": 74, "q": "Who most likely is the speaker?", "opts": ["A facilities manager", "A human resources representative", "A security officer", "A corporate executive"], "ans": 1, "ko": "화자가 초반부에 자신이 모든 오리엔테이션을 진행한다고 소개하면서 청자들의 직원 계정을 설정해야 한다(I facilitate all orientation sessions. Before we start today, you will need to set up your employee account)고 설명함. 이는 신입 사원들의 회사 적응을 돕는 인사부 직원의 업무에 해당하므로 정답은 (B)."}, {"n": 75, "q": "According to the speaker, what will the listeners find in a binder?", "opts": ["A map of the building", "An employment contract", "An identification badge", "Log-in credentials"], "ans": 3, "ko": "화자가 중반부에 교육용 바인더 첫 번째 페이지에 사용자 이름과 임시 비밀번호가 있다며, 그 정보를 이용해 로그인하라(If you look at the first page of your training binder, you'll see your username and a temporary password. ~ log in using those credentials)고 했으므로 정답은 (D)."}, {"n": 76, "q": "What does the speaker say about department files?", "opts": ["They are only accessible from company computers.", "They must be password protected.", "They must follow a specific naming convention.", "They must be archived annually."], "ans": 0, "ko": "화자가 부서 파일은 오직 회사 컴퓨터에서만 접근할 수 있다(you can only access them from your company computer)고 했으므로 정답은 (A)."}], "script": [{"sp": "M-Au", "en": "Welcome, new employees! My name is Diego, and I facilitate all orientation sessions. Before we start today, you will need to set up your employee account.", "ko": "환영합니다, 신입 사원 여러분! 제 이름은 디에고이며, 앞으로 모든 오리엔테이션을 진행하게 되었습니다. 오늘 시작하기에 앞서, 여러분은 직원 계정을 설정하셔야 할 것입니다."}, {"sp": "M-Au", "en": "If you look at the first page of your training binder, you'll see your username and a temporary password. Please open the laptops you were given this morning and log in using those credentials.", "ko": "교육용 바인더 첫 번째 페이지를 보시면, 사용자 이름과 임시 비밀번호가 보일 것입니다. 오늘 아침에 지급받으신 노트북 컴퓨터를 열어서 그 정보를 이용해 로그인하시기 바랍니다."}, {"sp": "M-Au", "en": "You will then be prompted to create your own password. Once that's complete, you'll have access to all your department's files. Please note that you can only access them from your company computer.", "ko": "그 후에는 개인 비밀번호를 만들도록 안내를 받으실 것입니다. 그것이 완료되는 대로, 여러분 부서의 모든 파일에 접근하실 수 있을 것입니다. 오직 여러분의 회사 컴퓨터에서만 접근할 수 있다는 점에 유의하시기 바랍니다."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "audio": "Test_01-77-79.mp3", "qs": [{"n": 77, "q": "Where does the speaker work?", "opts": ["At a laundry facility", "At an amusement park", "At a sports stadium", "At a fitness center"], "ans": 1, "ko": "전체 내용 관련 - 화자의 근무 장소. 초반부에 자신을 덴빌 놀이공원의 헤더 로스라고 소개(This is Heather Ross calling from Denville Amusement Park)하므로 정답은 (B) At an amusement park."}, {"n": 78, "q": "What does the speaker say about an item she ordered a month ago?", "opts": ["It arrived later than expected.", "It was damaged during delivery.", "She needs help assembling it.", "She is pleased with it."], "ans": 3, "ko": "세부 사항 관련 - 화자가 주문품에 대해 하는 말. 중반부에 약 한 달 전에 주문한 게임기를 언급하며 정말로 만족하고 있다(I'm really happy with my purchase)고 했으므로 정답은 (D) She is pleased with it. (am really happy with → is pleased with)."}, {"n": 79, "q": "What does the speaker ask the listener to confirm?", "opts": ["Whether a new product will be available soon", "When a replacement part will be shipped", "How long a warranty lasts", "Who to contact about future orders"], "ans": 0, "ko": "세부 사항 관련 - 화자의 요청 사항. 후반부에 청자의 회사에서 곧 신작 게임을 출시할 수도 있다는 얘기를 들었다며 다시 전화해서 그게 사실인지 알려 달라(I heard you may be releasing a new game soon. Could you call me back and let me know if that's true?)고 요청했으므로 정답은 (A) Whether a new product will be available soon."}], "script": [{"sp": "W-Br", "en": "Hello. This is Heather Ross calling from Denville Amusement Park. About a month ago, I ordered one of your new video-game machines, Space Defenders. I'm really happy with my purchase, since the game has been incredibly popular with our park guests! I'm considering buying some additional machines in the near future. I heard you may be releasing a new game soon. Could you call me back and let me know if that's true? Thanks!", "ko": "안녕하세요. 덴빌 놀이공원의 헤더 로스입니다. 약 한 달 전에, 귀사의 새 비디오 게임기 중 하나인 <스페이스 디펜더스>를 주문했어요. 구매한 것에 정말로 만족하고 있는데, 이 게임이 저희 공원 손님들에게 믿을 수 없을 정도로 인기가 있기 때문입니다! 가까운 미래에 추가 기계를 몇 대 구입하는 것을 고려하고 있습니다. 귀사에서 곧 신작 게임을 출시할 수도 있다는 얘기를 들었습니다. 제게 다시 전화 주셔서 그게 사실인지 알려 주시겠습니까? 감사합니다!"}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "audio": "Test_01-80-82.mp3", "qs": [{"n": 80, "q": "What type of product does the speaker's company make?", "opts": ["Furniture", "Luggage", "Bedding", "Clothing"], "ans": 3, "ko": "화자가 초반부에 회의 주제를 소개하면서 자사의 의류 매출(our clothing sales)을 언급했으므로 정답은 (D) Clothing."}, {"n": 81, "q": "What does the speaker recommend doing?", "opts": ["Manufacturing some products locally", "Offering free shipping", "Participating in a trade show", "Developing a new product line"], "ans": 0, "ko": "화자가 일부 의류를 이 지역에서 제조하기 시작할 것을 제안한다(I'm recommending that we start manufacturing some clothing locally)고 했으므로 정답은 (A) Manufacturing some products locally."}, {"n": 82, "q": "What will happen at the next meeting?", "opts": ["A vote will take place.", "A consultant will give a presentation.", "Some contracts will be updated.", "Safety procedures will be reviewed."], "ans": 1, "ko": "화자가 후반부에 컨설턴트를 고용했고 그 사람이 다음 이사회 회의에 와서 장단점을 설명할 것(I hired a consultant ~ He'll be at our next board meeting to explain the pros and cons of each)이라고 했으므로 정답은 (B) A consultant will give a presentation."}], "script": [{"sp": "W-Am", "en": "The first agenda item for our board meeting is the annual sales report.", "ko": "우리 이사회 회의의 첫 번째 안건은 연 매출 보고서입니다."}, {"sp": "", "en": "We're all disappointed by the drop in our clothing sales.", "ko": "우리는 모두 의류 매출 감소에 실망했습니다."}, {"sp": "", "en": "The decline is mostly due to distribution issues.", "ko": "이러한 감소는 대부분 유통 문제로 인한 것입니다."}, {"sp": "", "en": "Because our factories are all overseas, it takes too long for orders to reach customers.", "ko": "우리 공장이 모두 해외에 있기 때문에, 주문한 물건이 고객에게 도달하는 데 너무 오래 걸립니다."}, {"sp": "", "en": "So I'm recommending that we start manufacturing some clothing locally.", "ko": "따라서 일부 의류를 이 지역에서 제조하기 시작할 것을 제안합니다."}, {"sp": "", "en": "We'll be looking for a location to build a manufacturing facility.", "ko": "우리는 제조 시설을 지을 장소를 찾을 예정입니다."}, {"sp": "", "en": "I hired a consultant to put together a list of locations we could use.", "ko": "우리가 이용할 수 있을 만한 장소들의 목록을 만들어 줄 컨설턴트를 고용했습니다."}, {"sp": "", "en": "He'll be at our next board meeting to explain the pros and cons of each.", "ko": "이분께서 다음 이사회 회의에 오셔서 각각의 장단점을 설명해 주실 것입니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "audio": "Test_01-83-85.mp3", "qs": [{"n": 83, "q": "What is the announcement mainly about?", "opts": ["A promotional event", "A vacation package", "A building renovation", "A travel delay"], "ans": 3, "ko": "화자가 초반부에 미드웨이 역으로 향하는 모든 열차가 철로 수리로 인해 지연되었다(All trains to Midway Station are delayed for track repairs)고 언급한 뒤, 그에 따른 조치를 설명하고 있으므로 정답은 (D) 운행 지연."}, {"n": 84, "q": "Why does the speaker say, \"A bus will be departing for that destination in fifteen minutes\"?", "opts": ["To suggest an alternative arrangement", "To explain an extended wait time", "To recommend changing the travel date", "To inform customers about a new destination"], "ans": 0, "ko": "화자가 중반부에 많은 통근자들이 가능한 한 빨리 미드웨이로 가야 한다는 것을 안다(We understand that many commuters need to get to Midway as soon as possible)고 밝히면서 인용문을 언급하고 있다. 이는 통근자들의 신속한 이동을 위해 대체 교통 수단을 제공한다는 뜻이므로 정답은 (A) 대체 방안을 제안하기 위해."}, {"n": 85, "q": "What does the speaker remind the listeners about?", "opts": ["How to download a mobile application", "Where a waiting area is located", "How to reserve tickets", "Where to buy food"], "ans": 3, "ko": "화자가 후반부에 역내 카페가 오전 8시에 문을 열며, 1번 승강장에 음식 주문용 단말기가 있다는 사실을 상기시킨다(~ a reminder that the station café opens at eight A.M., and there are food kiosks on platform one)고 했으므로 정답은 (D) 음식을 구입하는 곳."}], "script": [{"sp": "M-Cn", "en": "Attention, passengers.", "ko": "승객 여러분, 주목해 주십시오."}, {"sp": "", "en": "All trains to Midway Station are delayed for track repairs.", "ko": "미드웨이 역으로 가는 모든 열차가 선로 보수로 인해 지연되고 있습니다."}, {"sp": "", "en": "Repair crews are working on a stretch of track just south of the town of Wheedon.", "ko": "보수 작업반이 위든 마을 바로 남쪽의 선로 구간에서 작업하고 있습니다."}, {"sp": "", "en": "They expect to complete the repair within the hour.", "ko": "그들은 한 시간 내에 보수를 완료할 것으로 예상합니다."}, {"sp": "", "en": "We apologize for the delay.", "ko": "지연에 대해 사과드립니다."}, {"sp": "", "en": "We understand that many commuters need to get to Midway as soon as possible.", "ko": "많은 통근자들이 가능한 한 빨리 미드웨이에 도착해야 한다는 것을 이해합니다."}, {"sp": "", "en": "A bus will be departing for that destination in fifteen minutes.", "ko": "그 목적지로 가는 버스가 15분 후에 출발할 것입니다."}, {"sp": "", "en": "Also, a reminder that the station café opens at eight A.M., and there are food kiosks on platform one.", "ko": "또한, 역 카페는 오전 8시에 문을 열며, 1번 승강장에 음식 가판대가 있다는 점을 알려드립니다."}, {"sp": "", "en": "Attention passengers. All trains to Midway Station are delayed for track repairs. Repair crews are working on the track just south of Weeden City. We expect the repairs to be completed within the hour. We apologize for the delay. We understand that many commuters need to get to Midway as soon as possible. A bus will be departing for that destination in fifteen minutes. And I'd like to remind you that the station café opens at eight A.M., and there are food kiosks on platform one.", "ko": "승객 여러분께 알립니다. 미드웨이 역으로 향하는 모든 열차가 철로 수리로 인해 지연되었습니다. 수리팀이 위든 시의 바로 남쪽 철로 구간에서 작업을 하고 있습니다. 한 시간 내로 수리를 완료할 것으로 예상하고 있습니다. 지연에 대해 사과드립니다. 저희는 많은 통근자들께서 가능한 한 빨리 미드웨이로 가셔야 한다는 것을 알고 있습니다. 그 목적지로 가는 버스가 15분 뒤에 출발할 예정입니다. 그리고 역내 카페가 오전 8시에 문을 열며, 1번 승강장에 음식 주문용 단말기가 있다는 사실을 상기시켜 드립니다."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "audio": "Test_01-86-88.mp3", "qs": [{"n": 86, "q": "Where does the speaker most likely work?", "opts": ["At a graphic design company", "At a law firm", "At a photography studio", "At a museum"], "ans": 0, "ko": "화자가 초반부에 소속 디자인팀이 청자 회사의 로고를 업데이트하기 위해 진행 중인 작업(~ the work my design team's doing to update your company logo)을 언급하므로 정답은 (A) 그래픽 디자인 회사."}, {"n": 87, "q": "What did the listener receive by e-mail?", "opts": ["A newsletter", "Some images", "An invoice", "Some contracts"], "ans": 1, "ko": "화자가 초반부에 청자 회사의 로고(your company logo)를 업데이트하는 작업을 언급하며 검토를 위해 두 가지 버전을 이메일로 보냈다(I've just e-mailed two versions for you to review)고 했으므로 정답은 (B) 이미지."}, {"n": 88, "q": "Why is the speaker unavailable next week?", "opts": ["She will be working at another branch.", "She will be with other clients.", "She will be on vacation.", "She will be at an industry conference."], "ans": 2, "ko": "화자가 후반부에 다음 주 내내 휴가 중일 것(I'll be on vacation all next week ~)이라고 했으므로 정답은 (C) 휴가 중일 것이다."}], "script": [{"sp": "W-Br", "en": "I'm calling about the work my design team's doing to update your company logo. I've just e-mailed two versions for you to review. The first is a modern design with bold colors and simple lettering. The second image reflects the history of your brand and its logo. It's less trendy, but it doesn't depart much from the original, which you may prefer. Take your time to think about which one you'd like to choose. I'll be on vacation all next week, but if you call the office, my assistant will set up a meeting for when I get back.", "ko": "저희 디자인팀이 귀사의 로고를 업데이트하기 위해 진행 중인 작업과 관련해 전화합니다. 제가 방금 검토해 보실 수 있도록 두 가지 버전을 이메일로 보내 드렸습니다. 첫 번째는 대담한 색상과 단순한 글자가 들어간 현대적인 디자인입니다. 두 번째 이미지는 귀사의 브랜드와 그 로고의 역사를 반영합니다. 덜 유행을 타지만, 원본에서 크게 벗어나지 않아 더 선호하실 수도 있습니다. 어느 것을 선택하고 싶으신지 시간을 갖고 생각해 보세요. 저는 다음 주 내내 휴가입니다만, 사무실로 전화 주시면 제 비서가 제가 돌아왔을 때를 위한 미팅을 잡아 드릴 것입니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "audio": "Test_01-89-91.mp3", "qs": [{"n": 89, "q": "Who most likely are the listeners?", "opts": ["Investors", "Government officials", "Engineers", "Journalists"], "ans": 3, "ko": "화자가 중반부에 청자들의 문의에 공식적으로 답변하기 위해 해당 기자 회견 일정을 잡았다(I've scheduled this press conference to officially respond to your inquiries)고 밝히므로 정답은 (D) Journalists."}, {"n": 90, "q": "What does the speaker mean when she says, \"All of ours are at least ten years old\"?", "opts": ["An event needs to be relocated.", "An upgrade is not feasible.", "A project team has a lot of experience.", "Some company policies are outdated."], "ans": 1, "ko": "업그레이드는 5년 미만 열차에만 경제적이라고 했으므로, 모두 최소 10년이 되었다는 말은 업그레이드가 경제적 효용성이 없어 실현하기 어렵다는 뜻이라 정답은 (B) An upgrade is not feasible."}, {"n": 91, "q": "According to the speaker, what can be requested by e-mail?", "opts": ["Some presentation slides", "Some product samples", "A report summary", "A discounted ticket"], "ans": 2, "ko": "더 자세한 정보에 관심이 있으면 언론 홍보팀에 이메일을 보내 결과 요약본을 받아 보라(e-mail our media relations department to receive a summary of the findings)고 했으므로 정답은 (C) A report summary."}], "script": [{"sp": "W-Am", "en": "After the transportation agency released the draft of our improvement plan last week, members of the press asked if we're considering installing more fuel-efficient engines in our trains.", "ko": "교통국에서 지난주에 개선 계획 초안을 공개한 후로, 기자들이 열차에 연비가 더 좋은 엔진을 설치하는 것을 고려하고 있는지 질문했습니다."}, {"sp": "", "en": "I've scheduled this press conference to officially respond to your inquiries.", "ko": "여러분의 문의에 공식적으로 답변해 드리기 위해 이 기자 회견 일정을 잡았습니다."}, {"sp": "", "en": "Eighteen months ago, we hired a firm to determine if this upgrade would be feasible for our trains.", "ko": "18개월 전에, 이 업그레이드를 실제로 열차에 적용할 수 있을지 알아보기 위해 업체를 고용했습니다."}, {"sp": "", "en": "It reported that the upgrade would be economical only for relatively new trains—that is, those less than five years old.", "ko": "그곳에서는 이 업그레이드가 오직 비교적 새 열차들, 다시 말해서, 연식이 5년 미만인 열차들에 대해서만 경제적일 것이라고 알려 주었습니다."}, {"sp": "", "en": "All of ours are at least ten years old.", "ko": "저희가 보유한 것들은 모두 최소 10년은 되었습니다."}, {"sp": "", "en": "I hope this addresses your questions.", "ko": "이것으로 여러분의 궁금증이 해결되기를 바랍니다."}, {"sp": "", "en": "If you're interested in more details, e-mail our media relations department to receive a summary of the findings.", "ko": "더 자세한 정보에 관심이 있으시면, 저희 언론 홍보팀에 이메일을 보내셔서 결과 요약본을 받아 보시기 바랍니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "audio": "Test_01-92-94.mp3", "qs": [{"n": 92, "q": "What does the speaker want to do?", "opts": ["Increase online sales", "Upgrade a payment system", "Create a new product line", "Add store locations"], "ans": 1, "ko": "화장품 매장에서 더욱 현대화된 결제 시스템 사용을 검토하고자 한다(I want to explore the use of a more modernized payment system)고 했으므로 정답은 (B) Upgrade a payment system."}, {"n": 93, "q": "According to the speaker, what is the customers' main complaint?", "opts": ["Long lines", "High prices", "Unavailable items", "Unfriendly staff"], "ans": 0, "ko": ""}, {"n": 94, "q": "Why does the speaker say, \"that's our busiest location\"?", "opts": ["To request some feedback", "To compliment some staff", "To express frustration", "To justify a choice"], "ans": 0, "ko": ""}], "script": [{"sp": "M-Cn", "en": "As regional sales manager, I want to explore the use of a more modernized payment system in our cosmetics stores.", "ko": "지역 영업 관리자로서, 저는 화장품 매장에서 더욱 현대화된 결제 시스템을 사용하는 것을 검토하고자 합니다."}, {"sp": "", "en": "This system would allow any sales associate to take customer payments from a tablet anywhere in the store.", "ko": "이 시스템은 영업 사원이 매장 내 어디서나 태블릿을 통해 고객 결제를 처리할 수 있게 해 줄 것입니다."}, {"sp": "", "en": "Why should we do this?", "ko": "우리가 왜 이렇게 해야 할까요?"}, {"sp": "", "en": "The main complaint about shopping at our stores is waiting in lines to pay.", "ko": "우리 매장에서 쇼핑하는 것과 관련된 주된 불만은 결제하기 위해 줄을 길게 서서 대기하는 것입니다."}, {"sp": "", "en": "A lot of our stores could benefit from this, but I've decided to conduct a trial run at our store in the Center City Mall.", "ko": "많은 매장들이 이것으로 혜택을 볼 수 있겠지만, 저는 센터 시티 몰에 있는 매장에서 시범 운영을 하기로 결정했습니다."}, {"sp": "", "en": "By far, that's our busiest location.", "ko": "단연코, 그곳이 가장 바쁜 지점입니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "audio": "Test_01-95-97.mp3", "qs": [{"n": 95, "q": "According to the speaker, what is special about the Reston Office Tower?", "opts": ["It features an indoor garden.", "It exhibits work from local artists.", "It runs on solar power.", "It has won many awards."], "ans": 1, "ko": ""}, {"n": 96, "q": "Look at the graphic. Which floors will be occupied in January?", "opts": ["Floors 1-5", "Floors 6-10", "Floors 11-14", "Floors 15-17"], "ans": 2, "ko": ""}, {"n": 97, "q": "What does the speaker say is available on a Web site?", "opts": ["Some photographs", "An event schedule", "A floor layout", "A recorded interview"], "ans": 3, "ko": ""}], "script": [], "gimg": "ets_t1_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "audio": "Test_01-98-100.mp3", "qs": [{"n": 98, "q": "Who most likely are the listeners?", "opts": ["Safety engineers", "Laboratory technicians", "Legal consultants", "Business investors"], "ans": 3, "ko": ""}, {"n": 99, "q": "Look at the graphic. Where will a new mine be built?", "opts": ["At site 1", "At site 2", "At site 3", "At site 4"], "ans": 2, "ko": ""}, {"n": 100, "q": "What does the speaker say is the next step?", "opts": ["Applying for permits", "Installing equipment", "Hiring additional staff", "Updating a manual"], "ans": 0, "ko": ""}], "script": [], "gimg": "ets_t1_g98.jpg"}]};
